    private final BCryptPasswordEncoder passwordEncoder = new BCryptPasswordEncoder();
    private final SecureRandom secureRandom = new SecureRandom();

    public void enableTwoFactorAuthentication(String username) {
        User user = userRepository.findByUsername(username);
        if (user != null) {
            user.setTwoFactorEnabled(true);
            user.setBackupCodes(generateBackupCodes());
            userRepository.save(user);
        }
    }

    private String generateBackupCodes() {
        List<String> codes = new ArrayList<>();
        for (int i = 0; i < 10; i++) {
            String code = KeyGenerators.string().generateKey();
            codes.add(passwordEncoder.encode(code));
        }
        return String.join(",", codes);
    }

    public boolean authenticateWithBackupCode(String username, String backupCode) {
        User user = userRepository.findByUsername(username);
        if (user != null && user.isTwoFactorEnabled()) {
            String[] codes = user.getBackupCodes().split(",");
            for (String code : codes) {
                if (passwordEncoder.matches(backupCode, code)) {
                    // Remove used code and save updated backup codes
                    user.setBackupCodes(String.join(",", removeUsedCode(codes, backupCode)));
                    userRepository.save(user);
                    return true;
                }
            }
        }
        return false;
    }

    private List<String> removeUsedCode(String[] codes, String usedCode) {
        List<String> updatedCodes = new ArrayList<>();
        for (String code : codes) {
            if (!passwordEncoder.matches(usedCode, code)) {
                updatedCodes.add(code);
            }
        }
        return updatedCodes;
    }
